    cat("--- Starting Study Session ---\n")
    cat("Press [Enter] for the next question, or type 'q' to quit.\n")
    
    solved_questions <- 1
    # 2. Outer loop: Restarts the whole sequence forever
    while(TRUE) {
        
        for (i in 1:length(soe_list)) {
            # lubridate lets you use ymd() (year-month-day) easily
            future_date <- lubridate::ymd("2026-06-26")
            now <- today()
            days_between <- time_length(future_date - now, unit = "days")
            
            
            current_set <- soe_list[[i]]
            selected_q <- sample(current_set, size = 1)
            
            
            cat("\nDAYS LEFT: [", days_between, "]")
            cat("\nQUESTIONS SOLVED: [", solved_questions, "]")
            
            # Print the SOE and the question 
            cat("\nSECTION: [", names(soe_list)[i], "]")
            cat("\nQUESTION:", selected_q, "\n")
            
            # 4. Wait for user input
            cat("\nNext", "> ")
            usr_input <- readLines(file("stdin"), n = 1)
            
            if (names(soe_list)[i] %in% c("ABC_Verbal", "WTF", "clinical_anaesthesia", "pharmacology_clinical_measurements", "physics_physiology", "physics_physiology", "anatomy", "best_book", "anae_doc")) {
                solved_questions <- solved_questions + 1
            }
            
            # Check for quit command
            if (tolower(usr_input) == "q") {
                cat("\nExiting", "Good luck with your exam \n")
                return() 
            }
        }
        
        cat("\n*** Completed one round - GO FOR CLINICAL and ALTO-PHARMACOLOGY ... ***\n")
    }
}

run()







